import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Menu, X } from 'lucide-react';

export default function Navbar() {
  const [isOpen, setIsOpen] = useState(false);

  const navLinks = [
    { name: 'Home', href: '/' },
    { name: 'Services', href: '/services' },
    { name: 'Portfolio', href: '/portfolio' },
    { name: 'About', href: '/about' },
    { name: 'Contact', href: '/contact' },
  ];

  return (
    <nav className="fixed top-0 left-0 w-full z-50 bg-gradient-to-b from-zinc-950 to-zinc-900 border-b border-zinc-800 shadow-2xl py-4"DM Sans']">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          {/* Brand Name and Tagline */}
          <div className="flex-shrink-0">
            <Link to="/" className="flex flex-col items-start group">
              <span className="text-2xl font-bold tracking-tight text-zinc-50 group-hover:text-zinc-100 transition-colors duration-200">
                PixelPulse Studio
              </span>
              <span className="text-sm text-zinc-400 group-hover:text-zinc-300 transition-colors duration-200 mt-1">
                Crafting digital experiences with passion and precision.
              </span>
            </Link>
          </div>

          {/* Desktop Navigation */}
          <div className="hidden md:flex space-x-8">
            {navLinks.map((link) => (
              <Link
                key={link.name}
                to={link.href}
                className="text-zinc-300 hover:text-zinc-50 hover:bg-zinc-700 px-3 py-2 rounded-xl transition-all duration-300 ease-in-out font-medium text-lg"
              >
                {link.name}
              </Link>
            ))}
          </div>

          {/* Mobile Menu Button */}
          <div className="-mr-2 flex md:hidden">
            <button
              onClick={() => setIsOpen(!isOpen)}
              type="button"
              className="inline-flex items-center justify-center p-2 rounded-xl text-zinc-400 hover:text-zinc-50 hover:bg-zinc-800 focus:outline-none focus:ring-2 focus:ring-inset focus:ring-zinc-600 transition-all duration-200"
              aria-controls="mobile-menu"
              aria-expanded="false"
            >
              <span className="sr-only">Open main menu</span>
              {isOpen ? (
                <X className="block h-7 w-7" />
              ) : (
                <Menu className="block h-7 w-7" />
              )}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu Panel */}
      {isOpen && (
        <div className="md:hidden mt-4 px-2 pt-2 pb-3 space-y-2 border-t border-zinc-800 bg-zinc-900 shadow-xl" id="mobile-menu">
          {navLinks.map((link) => (
            <Link
              key={link.name}
              to={link.href}
              onClick={() => setIsOpen(false)}
              className="block px-3 py-2 rounded-xl text-base font-medium text-zinc-300 hover:text-zinc-50 hover:bg-zinc-700 transition-all duration-200"
            >
              {link.name}
            </Link>
          ))}
        </div>
      )}
    </nav>
  );
}"

